class Store{constructor(){this.db=null;this.mode='idb';this.key='vector_ats_local_v1'}async init(){if(!window.indexedDB){this.mode='local';return}try{this.db=await new Promise((ok,no)=>{let r=indexedDB.open(DB_NAME,DB_VERSION);r.onupgradeneeded=()=>{let d=r.result;STORES.forEach(s=>{if(!d.objectStoreNames.contains(s))d.createObjectStore(s,{keyPath:'id'})})};r.onsuccess=()=>ok(r.result);r.onerror=()=>no(r.error)})}catch{this.mode='local'}}read(){try{return JSON.parse(localStorage.getItem(this.key)||'{}')}catch{return {}}}write(v){localStorage.setItem(this.key,JSON.stringify(v))}async all(s){if(this.mode==='local')return(this.read()[s]||[]).slice();return new Promise((ok,no)=>{let r=this.db.transaction(s,'readonly').objectStore(s).getAll();r.onsuccess=()=>ok(r.result||[]);r.onerror=()=>no(r.error)})}async clear(s){if(this.mode==='local'){let d=this.read();d[s]=[];this.write(d);return}return new Promise((ok,no)=>{let t=this.db.transaction(s,'readwrite');t.objectStore(s).clear();t.oncomplete=()=>ok();t.onerror=()=>no(t.error)})}async put(s,row){if(this.mode==='local'){let d=this.read();d[s]=d[s]||[];let i=d[s].findIndex(x=>x.id===row.id);if(i>=0)d[s][i]=row;else d[s].push(row);this.write(d);return row}return new Promise((ok,no)=>{let t=this.db.transaction(s,'readwrite');t.objectStore(s).put(row);t.oncomplete=()=>ok(row);t.onerror=()=>no(t.error)})}async bulk(s,rows){if(this.mode==='local'){let d=this.read();d[s]=rows.slice();this.write(d);return}return new Promise((ok,no)=>{let t=this.db.transaction(s,'readwrite'),o=t.objectStore(s);rows.forEach(r=>o.put(r));t.oncomplete=()=>ok();t.onerror=()=>no(t.error)})}}
