function inferAccessRoleId(user){let name=String(user.role||'').toLowerCase();if(name.includes('admin'))return'user' in user&&user.id==='usr_08'?'role_ta_ops_admin':'role_super_admin';if(name.includes('lead recruiter'))return'role_recruiter_admin';if(name.includes('recruiter')||name.includes('talent partner'))return'role_recruiter';if(name.includes('coordinator'))return'role_coordinator';if(name.includes('hiring manager'))return'role_hiring_manager';return'role_interviewer'}
function accessPresetDefaults(user,roleId){let scopeType=roleId==='role_super_admin'||roleId==='role_ta_ops_admin'?'global':roleId==='role_recruiter_admin'||roleId==='role_recruiter'?'department':roleId==='role_interviewer'?'interview':'job',scopeValue=scopeType==='global'?'Organization':scopeType==='department'?(A.lu.dep[user.departmentId]?.name||user.team||'Talent Acquisition'):scopeType==='interview'?'Assigned interviews':'All assigned jobs';return{scopeType,scopeValue,seatType:roleId==='role_interviewer'?'Light':'Full',canManageRoles:roleId==='role_super_admin'||roleId==='role_ta_ops_admin',canViewCompensation:!['role_interviewer','role_coordinator'].includes(roleId)}}
function defaultAccessAssignment(user){let roleId=inferAccessRoleId(user),preset=accessPresetDefaults(user,roleId);return{roleId,...preset,status:user.status||'Active',lastReviewedAt:iso(ago(7))}}
function accessSettings(){let raw=pj(localStorage.getItem(ACCESS_SETTINGS_KEY),{});if(!raw||typeof raw!=='object')raw={};let users=raw.users&&typeof raw.users==='object'?raw.users:{};A.cache.users.forEach(user=>{if(!users[user.id])users[user.id]=defaultAccessAssignment(user)});return{users,policies:{approvalChain:raw.policies?.approvalChain||'Role + scope',privateNotesVisibility:raw.policies?.privateNotesVisibility||'Recruiters and hiring managers',offerVisibility:raw.policies?.offerVisibility||'Recruiters and approvers',scorecardVisibility:raw.policies?.scorecardVisibility||'Interview panel only',enforceMfa:!!raw.policies?.enforceMfa,requireSso:!!raw.policies?.requireSso,inviteExpiryDays:Number(raw.policies?.inviteExpiryDays||14)}}}
function writeAccessSettings(next){localStorage.setItem(ACCESS_SETTINGS_KEY,JSON.stringify(next))}
function currentAccessAssignment(){let user=current();return accessSettings().users[user.id]||defaultAccessAssignment(user)}
function accessScopeLabel(scopeType){if(scopeType==='global')return'Global';if(scopeType==='department')return'Department';if(scopeType==='client')return'Client';if(scopeType==='interview')return'Interview';return'Assigned jobs'}
function accessScopeSummary(assignment){if(!assignment)return'Not configured';if(assignment.scopeType==='global')return'Global access';return`${accessScopeLabel(assignment.scopeType)}: ${assignment.scopeValue||'Defined by admin'}`}
function accessPermissionMap(assignment){let role=accessRoleById(assignment?.roleId),overrides=assignment&&assignment.permissionOverrides&&typeof assignment.permissionOverrides==='object'?assignment.permissionOverrides:{};return {...role.permissions,...overrides}}
function accessLevelRank(level){let idx=ACCESS_PERMISSION_LEVELS.indexOf(String(level||'None'));return idx<0?0:idx}
function accessPermissionLevel(moduleKey,assignment=currentAccessAssignment()){return accessPermissionMap(assignment)[moduleKey]||'None'}
function hasModulePermission(moduleKey,min='View',assignment=currentAccessAssignment()){if(!moduleKey)return true;return accessLevelRank(accessPermissionLevel(moduleKey,assignment))>=accessLevelRank(min)}
function routePermissionKey(route){return ROUTE_PERMISSION_KEYS[route]||''}
function canAccessRoute(route,assignment=currentAccessAssignment()){if(route==='dashboard')return true;let key=routePermissionKey(route),min=route==='pipeline'?'Limited':'View';return key?hasModulePermission(key,min,assignment):true}
function visibleRoutes(){let routes=ROUTES.filter(route=>canAccessRoute(route));return routes.length?routes:['dashboard']}
function firstAccessibleRoute(){return visibleRoutes().find(route=>route!=='dashboard')||'dashboard'}
function resolveAccessibleRoute(route){return canAccessRoute(route)?route:firstAccessibleRoute()}
function ensureRouteAccess(pushHash=false){let next=resolveAccessibleRoute(A.ui.route);if(A.ui.route!==next){A.ui.route=next;if(pushHash)location.hash='#/'+next}return next}
function accountUsers(){let q=String(A.ui.accountQuery||'').trim().toLowerCase();return A.cache.users.slice().sort((a,b)=>a.fullName.localeCompare(b.fullName)).filter(user=>!q||`${user.fullName} ${user.email||''} ${user.role||''}`.toLowerCase().includes(q))}
function canUseQuickAdd(){return hasModulePermission('candidates','Edit')||hasModulePermission('jobs','Edit')||hasModulePermission('applications','Edit')||hasModulePermission('interviews','Edit')}
function canOpenDrawerModule(mod){let routeKey=routePermissionKey(mod),min=mod==='applications'?'Limited':'View';return routeKey?hasModulePermission(routeKey,min):true}
function modalPermission(type){if(type==='candidate')return hasModulePermission('candidates','Edit');if(type==='client'||type==='job')return hasModulePermission('jobs','Edit');if(type==='submitCandidate'||type==='stagebulk'||type==='assignowner'||type==='rejectapps')return hasModulePermission('applications','Edit');if(type==='interview'||type==='rescheduleInterview')return hasModulePermission('interviews','Edit');if(type==='saveview')return true;if(type==='note')return hasModulePermission('applications','Limited')||hasModulePermission('candidates','Limited');if(type==='quick')return canUseQuickAdd();return true}
function accessScopedJobIds(assignment=currentAccessAssignment(),user=current()){let rows=A.cache.job_openings||[];if(!rows.length)return[];if(assignment.scopeType==='global')return rows.map(job=>job.id);if(assignment.scopeType==='department'){let scope=String(assignment.scopeValue||'').toLowerCase();return rows.filter(job=>job.departmentId===user.departmentId||String(A.lu.dep[job.departmentId]?.name||'').toLowerCase()===scope).map(job=>job.id)}if(assignment.scopeType==='client'){let scope=String(assignment.scopeValue||'').toLowerCase();return rows.filter(job=>{let client=A.lu.clients[job.clientId];if(!client)return false;let hay=`${client.id} ${client.name}`.toLowerCase();return !scope?client.ownerUserId===user.id:hay.includes(scope)||client.ownerUserId===user.id}).map(job=>job.id)}if(assignment.scopeType==='interview'){let fullName=String(user.fullName||'').toLowerCase();return uniq((A.cache.interviews||[]).filter(interview=>interview.organizerUserId===user.id||String(interview.interviewers||'').toLowerCase().includes(fullName)).map(interview=>interview.jobOpeningId).filter(Boolean))}return rows.filter(job=>job.recruiterUserId===user.id||job.hiringManagerUserId===user.id||pj(job.assignedRecruiterIds,[]).includes(user.id)).map(job=>job.id)}
function accessScopedApplicationIds(assignment=currentAccessAssignment(),user=current()){let jobIds=new Set(accessScopedJobIds(assignment,user));return (A.cache.applications||[]).filter(app=>jobIds.has(app.jobOpeningId)||app.ownerUserId===user.id).map(app=>app.id)}
function accessScopedCandidateIds(assignment=currentAccessAssignment(),user=current()){let appIds=new Set(accessScopedApplicationIds(assignment,user)),candidateIds=new Set((A.cache.applications||[]).filter(app=>appIds.has(app.id)).map(app=>app.candidateId));return (A.cache.candidates||[]).filter(candidate=>candidateIds.has(candidate.id)||candidate.ownerUserId===user.id||(assignment.scopeType==='department'&&A.lu.users[candidate.ownerUserId]?.departmentId===user.departmentId)).map(candidate=>candidate.id)}
function accessScopedInterviewIds(assignment=currentAccessAssignment(),user=current()){let appIds=new Set(accessScopedApplicationIds(assignment,user)),fullName=String(user.fullName||'').toLowerCase();return (A.cache.interviews||[]).filter(interview=>appIds.has(interview.applicationId)||interview.organizerUserId===user.id||String(interview.interviewers||'').toLowerCase().includes(fullName)).map(interview=>interview.id)}
function accessScopedOfferIds(assignment=currentAccessAssignment(),user=current()){let appIds=new Set(accessScopedApplicationIds(assignment,user));return (A.cache.offers||[]).filter(offer=>appIds.has(offer.applicationId)).map(offer=>offer.id)}
function accessScopedClientIds(assignment=currentAccessAssignment(),user=current()){let jobIds=new Set(accessScopedJobIds(assignment,user)),clientIds=new Set((A.cache.job_openings||[]).filter(job=>jobIds.has(job.id)).map(job=>job.clientId));return (A.cache.clients||[]).filter(client=>clientIds.has(client.id)||client.ownerUserId===user.id).map(client=>client.id)}
function accessFilterRows(moduleName,rows){if(moduleName==='jobs'){if(!hasModulePermission('jobs','View'))return[];let ids=new Set(accessScopedJobIds());return rows.filter(row=>ids.has(row.id))}if(moduleName==='applications'){if(!hasModulePermission('applications','Limited'))return[];let ids=new Set(accessScopedApplicationIds());return rows.filter(row=>ids.has(row.id))}if(moduleName==='candidates'){if(!hasModulePermission('candidates','Limited'))return[];let ids=new Set(accessScopedCandidateIds());return rows.filter(row=>ids.has(row.id))}if(moduleName==='interviews'){if(!hasModulePermission('interviews','View'))return[];let ids=new Set(accessScopedInterviewIds());return rows.filter(row=>ids.has(row.id))}if(moduleName==='offers'){if(!hasModulePermission('offers','View'))return[];let ids=new Set(accessScopedOfferIds());return rows.filter(row=>ids.has(row.id))}if(moduleName==='clients'){if(!hasModulePermission('jobs','View'))return[];let ids=new Set(accessScopedClientIds());return rows.filter(row=>ids.has(row.id))}return rows}
function moneyVisible(value,currency='USD'){return currentAccessAssignment().canViewCompensation?money(value,currency):'Restricted'}
function csvItems(value){return uniq(String(value||'').split(',').map(item=>item.trim()).filter(Boolean))}
function schemaTable(rows){return `<table class="schemaTable"><thead><tr><th>Field</th><th>Type</th><th>Meaning</th></tr></thead><tbody>${rows.map(([field,type,purpose])=>`<tr><td><strong>${esc(field)}</strong></td><td>${esc(type)}</td><td>${esc(purpose)}</td></tr>`).join('')}</tbody></table>`}
function reportWorkspace(){let raw=pj(localStorage.getItem(REPORTS_LIBRARY_KEY),{});if(!raw||typeof raw!=='object')raw={};return {...DEFAULT_REPORTS_WORKSPACE,...raw,customFolders:Array.isArray(raw.customFolders)?raw.customFolders:[],customReports:Array.isArray(raw.customReports)?raw.customReports:[],favorites:Array.isArray(raw.favorites)?raw.favorites.slice():DEFAULT_REPORTS_WORKSPACE.favorites.slice(),recent:Array.isArray(raw.recent)?raw.recent.slice():DEFAULT_REPORTS_WORKSPACE.recent.slice(),deleted:Array.isArray(raw.deleted)?raw.deleted.slice():[],scheduled:Array.isArray(raw.scheduled)?raw.scheduled.slice():DEFAULT_REPORTS_WORKSPACE.scheduled.slice(),folderOverrides:raw.folderOverrides&&typeof raw.folderOverrides==='object'?raw.folderOverrides:{}}}
function writeReportWorkspace(next){localStorage.setItem(REPORTS_LIBRARY_KEY,JSON.stringify(next))}
function reportState(){let s=state('reports'),cfg=adminSettings();if(!s.range)s.range=cfg.reportDefaultRange;if(!s.departmentId)s.departmentId='all';if(!s.recruiterId)s.recruiterId='all';if(!s.sourceType)s.sourceType='all';if(!s.folder)s.folder='recent_reports';if(typeof s.detail!=='boolean')s.detail=false;if(!s.builder)s.builder=reportBuilderState();return s}
function settingsState(){let s=state('settings');if(!s.tab)s.tab='general';if(!s.userId)s.userId=current().id;return s}
function settingsTabNav(activeTab){return `<nav class="settingsnav">${SETTINGS_TABS.map(([id,label])=>`<button class="settingtab ${activeTab===id?'on':''}" type="button" data-a="settingsTab" data-tab="${id}"><strong>${esc(label)}</strong></button>`).join('')}</nav>`}
function settingsRolePermissionGrid(role,assignment){let permissionMap=accessPermissionMap(assignment);return `<div class="settingpermgrid">${ACCESS_PERMISSION_GROUPS.map(([key,label])=>`<label class="settingperm"><span>${esc(label)}</span><select name="perm_${key}">${ACCESS_PERMISSION_LEVELS.map(value=>`<option value="${value}" ${permissionMap[key]===value?'selected':''}>${value}</option>`).join('')}</select></label>`).join('')}</div>`}
function settingsRoleCards(selectedRoleId){return `<div class="settingrolegrid">${ACCESS_ROLE_LIBRARY.map(role=>`<button class="settingrolecard ${role.id===selectedRoleId?'on':''}" type="button" data-a="settingsRolePreset" data-role-id="${role.id}"><strong>${esc(role.name)}</strong><small>${esc(role.scopeLabel)}</small><span>${esc(role.description)}</span></button>`).join('')}</div>`}
function settingsUserList(ws,selectedId){let users=A.cache.users.slice().sort((a,b)=>a.fullName.localeCompare(b.fullName));return `<section class="panel"><div class="hd"><h3>Team Members</h3><span class="sub">${users.length} users</span></div><div class="bd" style="padding-top:0"><div class="settingsuserlist">${users.map(user=>{let assignment=ws.users[user.id]||defaultAccessAssignment(user),role=accessRoleById(assignment.roleId),login=user.lastLoginAt?reportRelativeTime(user.lastLoginAt):(user.invitedAt?'Invited':'No login');return `<button class="settingsuserrow ${selectedId===user.id?'on':''}" type="button" data-a="settingsSelectUser" data-id="${user.id}"><div><strong>${esc(user.fullName)}</strong><small>${esc(role.name)} | ${esc(login)}</small></div>${pill(assignment.status||user.status||'Active')}</button>`}).join('')}</div></div></section>`}
function settingsGeneralView(){let cfg=adminSettings(),workflowId=selectedWorkflowId(),editable=hasModulePermission('settings','Edit'),notice=editable?'':`<section class="panel"><div class="bd"><div class="accessnotice">This user has read-only settings access. Save actions are hidden.</div></div></section>`;return `${notice}<form data-form="settingsGeneral" class="settingstack"><section class="panel"><div class="hd"><h3>Organization</h3></div><div class="bd"><div class="fg"><div class="field"><label>Company Name</label><input name="companyName" value="${esc(cfg.companyName)}" required></div><div class="field"><label>Legal Entity</label><input name="legalEntity" value="${esc(cfg.legalEntity)}"></div><div class="field"><label>Careers Site</label><input name="careersSite" value="${esc(cfg.careersSite)}"></div><div class="field"><label>Support Email</label><input type="email" name="supportEmail" value="${esc(cfg.supportEmail)}"></div><div class="field"><label>Headquarters</label><input name="headquarters" value="${esc(cfg.headquarters)}"></div><div class="field"><label>Primary Timezone</label><input name="primaryTimezone" value="${esc(cfg.primaryTimezone)}"></div><div class="field"><label>Locale</label><select name="locale">${['en-US','en-GB'].map(value=>`<option value="${value}" ${cfg.locale===value?'selected':''}>${value}</option>`).join('')}</select></div><div class="field"><label>Week Starts On</label><select name="weekStartsOn">${['Monday','Sunday'].map(value=>`<option value="${value}" ${cfg.weekStartsOn===value?'selected':''}>${value}</option>`).join('')}</select></div><div class="field"><label>Default Currency</label><select name="defaultCurrency">${['USD','INR','GBP','EUR'].map(value=>`<option value="${value}" ${cfg.defaultCurrency===value?'selected':''}>${value}</option>`).join('')}</select></div><div class="field"><label>Date Format</label><select name="dateFormat">${['MMM D, YYYY','DD MMM YYYY','YYYY-MM-DD'].map(value=>`<option value="${value}" ${cfg.dateFormat===value?'selected':''}>${value}</option>`).join('')}</select></div><div class="field"><label>Report Default Range</label><select name="reportDefaultRange">${REPORT_RANGE_OPTIONS.map(([value,label])=>`<option value="${value}" ${String(cfg.reportDefaultRange)===value?'selected':''}>${label}</option>`).join('')}</select></div></div></div></section><section class="panel"><div class="hd"><h3>Recruiting Defaults</h3></div><div class="bd"><div class="fg"><div class="field"><label>Default Workflow</label><select name="workflowDefault">${A.cache.workflows.map(item=>`<option value="${item.id}" ${workflowId===item.id?'selected':''}>${esc(item.name)}</option>`).join('')}</select></div><div class="field"><label>Offer Approval Flow</label><select name="offerApprovalFlow">${['Two-step','Manager approval','Recruiter only'].map(value=>`<option value="${value}" ${cfg.offerApprovalFlow===value?'selected':''}>${value}</option>`).join('')}</select></div><div class="field"><label>Video Provider</label><select name="defaultVideoProvider">${VIDEO_PROVIDER_OPTIONS.map(value=>`<option value="${esc(value)}" ${cfg.defaultVideoProvider===value?'selected':''}>${esc(value)}</option>`).join('')}</select></div><div class="field"><label>Interview Duration</label><select name="defaultInterviewDuration">${[30,45,60,90].map(value=>`<option value="${value}" ${Number(cfg.defaultInterviewDuration)===value?'selected':''}>${value} minutes</option>`).join('')}</select></div><div class="field"><label>Reminder Timing</label><select name="defaultReminder">${INTERVIEW_REMINDERS.map(value=>`<option value="${esc(value)}" ${cfg.defaultReminder===value?'selected':''}>${esc(value)}</option>`).join('')}</select></div><div class="field"><label>Pipeline Aging Days</label><input type="number" min="1" name="candidateAgingDays" value="${esc(cfg.candidateAgingDays)}"></div><div class="field"><label>Data Freshness Days</label><input type="number" min="1" name="dataFreshnessDays" value="${esc(cfg.dataFreshnessDays)}"></div><div class="field"><label>Shortlist Target</label><input type="number" min="1" name="shortlistTarget" value="${esc(cfg.shortlistTarget)}"></div><div class="field"><label>Privacy Retention Days</label><input type="number" min="30" name="privacyRetentionDays" value="${esc(cfg.privacyRetentionDays)}"></div></div><div class="switchstack" style="margin-top:16px"><label class="switchcard"><span><strong>Auto-assign applications</strong><small>New applications default to the job owner when possible.</small></span><input type="checkbox" name="autoAssignApplications" ${cfg.autoAssignApplications?'checked':''}></label><label class="switchcard"><span><strong>Auto-create follow-up tasks</strong><small>Keep recruiter execution queues warm by default.</small></span><input type="checkbox" name="autoCreateFollowupTasks" ${cfg.autoCreateFollowupTasks?'checked':''}></label><label class="switchcard"><span><strong>Require rejection reason</strong><small>Enforce structured close-out data for pipeline analytics.</small></span><input type="checkbox" name="requireRejectionReason" ${cfg.requireRejectionReason?'checked':''}></label><label class="switchcard"><span><strong>Require interview feedback</strong><small>Keep scorecards complete before downstream moves.</small></span><input type="checkbox" name="requireInterviewFeedback" ${cfg.requireInterviewFeedback?'checked':''}></label><label class="switchcard"><span><strong>Mask compensation for interviewers</strong><small>Restrict comp visibility for lower-privilege collaborators.</small></span><input type="checkbox" name="maskCompensationForInterviewers" ${cfg.maskCompensationForInterviewers?'checked':''}></label><label class="switchcard"><span><strong>Enable duplicate candidate check</strong><small>Reduce duplicate profiles before they hit the pipeline.</small></span><input type="checkbox" name="enableCandidateDupCheck" ${cfg.enableCandidateDupCheck?'checked':''}></label></div></div></section><section class="panel"><div class="hd"><h3>Workflow SLAs and Catalogs</h3></div><div class="bd"><div class="fg"><div class="field"><label>Applied SLA (days)</label><input type="number" min="1" name="slaApplied" value="${esc(cfg.slaDays.Applied)}"></div><div class="field"><label>Recruiter Screen SLA</label><input type="number" min="1" name="slaRecruiterScreen" value="${esc(cfg.slaDays['Recruiter Screen'])}"></div><div class="field"><label>Hiring Manager SLA</label><input type="number" min="1" name="slaHiringManager" value="${esc(cfg.slaDays['Hiring Manager'])}"></div><div class="field"><label>Interview Loop SLA</label><input type="number" min="1" name="slaInterviewLoop" value="${esc(cfg.slaDays['Interview Loop'])}"></div><div class="field"><label>Assessment SLA</label><input type="number" min="1" name="slaAssessment" value="${esc(cfg.slaDays.Assessment)}"></div><div class="field"><label>Offer SLA</label><input type="number" min="1" name="slaOffer" value="${esc(cfg.slaDays.Offer)}"></div><div class="field full"><label>Candidate Source Catalog</label><textarea name="candidateSourceCatalog" placeholder="Referral, LinkedIn, Career Site">${esc(cfg.candidateSourceCatalog)}</textarea></div><div class="field full"><label>Candidate Tag Catalog</label><textarea name="candidateTagCatalog" placeholder="Backend, Frontend, Product">${esc(cfg.candidateTagCatalog)}</textarea></div></div></div></section>${editable?`<section class="panel"><div class="bd settingssave"><button class="btnp" type="submit">Save General Settings</button></div></section>`:''}</form>`}
function settingsAccessView(){let s=settingsState(),ws=accessSettings(),selectedUser=A.lu.users[s.userId]||current(),assignment=ws.users[selectedUser.id]||defaultAccessAssignment(selectedUser),role=accessRoleById(assignment.roleId),editable=hasModulePermission('settings','Edit'),notice=editable?'':`<section class="panel"><div class="bd"><div class="accessnotice">This user can review access settings but cannot save changes.</div></div></section>`;return `<div class="settingsuserlayout">${settingsUserList(ws,selectedUser.id)}<div class="settingstack">${notice}<section class="panel"><div class="hd"><h3>${esc(selectedUser.fullName)}</h3></div></section><form data-form="settingsUserAccess" class="settingstack"><input type="hidden" name="userId" value="${esc(selectedUser.id)}"><section class="panel"><div class="hd"><h3>User Access</h3></div><div class="bd"><div class="fg"><div class="field"><label>Role</label><select name="roleId" data-a="settingsRoleTemplate">${ACCESS_ROLE_LIBRARY.map(item=>`<option value="${item.id}" ${item.id===assignment.roleId?'selected':''}>${esc(item.name)}</option>`).join('')}</select></div><div class="field"><label>Scope Type</label><select name="scopeType">${[['global','Global'],['department','Department'],['job','Assigned jobs'],['client','Client'],['interview','Interview']].map(([value,label])=>`<option value="${value}" ${assignment.scopeType===value?'selected':''}>${label}</option>`).join('')}</select></div><div class="field"><label>Scope Value</label><input name="scopeValue" value="${esc(assignment.scopeValue||'')}"></div><div class="field"><label>Seat Type</label><select name="seatType">${['Full','Light'].map(value=>`<option value="${value}" ${assignment.seatType===value?'selected':''}>${value}</option>`).join('')}</select></div><div class="field"><label>Status</label><select name="status">${['Active','Invited','Suspended','Inactive'].map(value=>`<option value="${value}" ${String(assignment.status||selectedUser.status)===value?'selected':''}>${value}</option>`).join('')}</select></div><div class="field"><label>Department</label><input value="${esc(A.lu.dep[selectedUser.departmentId]?.name||selectedUser.team||'-')}" readonly></div></div><div class="switchstack" style="margin-top:16px"><label class="switchcard"><span><strong>Can manage roles</strong><small>Allow this user to update access assignments for others.</small></span><input type="checkbox" name="canManageRoles" ${assignment.canManageRoles?'checked':''}></label><label class="switchcard"><span><strong>Can view compensation</strong><small>Hide salary-sensitive UI if this is turned off for the signed-in user.</small></span><input type="checkbox" name="canViewCompensation" ${assignment.canViewCompensation?'checked':''}></label></div></div></section><section class="panel"><div class="hd"><h3>Effective Permissions</h3></div><div class="bd">${settingsRolePermissionGrid(role,assignment)}</div></section>${editable?`<section class="panel"><div class="bd settingssave"><button class="btnp" type="submit">Save User Access</button></div></section>`:''}</form><section class="panel"><div class="hd"><h3>Role Presets</h3></div><div class="bd">${settingsRoleCards(role.id)}</div></section><form data-form="settingsAccessPolicy" class="settingstack"><section class="panel"><div class="hd"><h3>Access Policies</h3></div><div class="bd"><div class="fg"><div class="field"><label>Approval Chain</label><select name="approvalChain">${['Role + scope','Manager approval','Ops approval'].map(value=>`<option value="${value}" ${ws.policies.approvalChain===value?'selected':''}>${value}</option>`).join('')}</select></div><div class="field"><label>Invite Expiry (days)</label><input type="number" min="1" name="inviteExpiryDays" value="${esc(ws.policies.inviteExpiryDays)}"></div><div class="field"><label>Private Notes Visibility</label><select name="privateNotesVisibility">${['Recruiters and hiring managers','Recruiters only','Admins only'].map(value=>`<option value="${value}" ${ws.policies.privateNotesVisibility===value?'selected':''}>${value}</option>`).join('')}</select></div><div class="field"><label>Offer Visibility</label><select name="offerVisibility">${['Recruiters and approvers','Recruiters only','Leadership only'].map(value=>`<option value="${value}" ${ws.policies.offerVisibility===value?'selected':''}>${value}</option>`).join('')}</select></div><div class="field"><label>Scorecard Visibility</label><select name="scorecardVisibility">${['Interview panel only','Recruiters and panel','Hiring managers and panel'].map(value=>`<option value="${value}" ${ws.policies.scorecardVisibility===value?'selected':''}>${value}</option>`).join('')}</select></div></div></div></section>${editable?`<section class="panel"><div class="bd settingssave"><button class="btnp" type="submit">Save Access Policies</button></div></section>`:''}</form></div></div>`}
function reportMatchRange(value,range){if(!value||range==='all')return true;let d=new Date(value);return!Number.isNaN(d.getTime())&&d>=shift(NOW,-Number(range||30))}
function avgNum(rows,pickValue){return rows.length?Math.round(rows.reduce((sum,row)=>sum+Number(pickValue(row)||0),0)/rows.length):0}
function pct(num,den){return den?Math.round(num/den*100):0}
