function selectedWorkflowId(){let cfg=adminSettings();return A.cache.workflows.find(w=>w.id===cfg.workflowDefault)?.id||(A.cache.workflows.find(w=>w.isDefault)?.id)||A.cache.workflows[0]?.id||'wf_01'}
