function pipeline(){let pipeState=state('pipeline'),jobs=A.cache.job_openings.filter(j=>j.status==='Open'||j.status==='On Hold'),rows=applicationRows().filter(a=>!['Rejected','Withdrawn','Hired'].includes(a.overallStatus)),list=A.ui.pipeJob==='all'?rows:rows.filter(a=>a.jobOpeningId===A.ui.pipeJob),wf=A.ui.pipeJob==='all'?'wf_01':A.lu.jobs[A.ui.pipeJob].workflowId,stages=(A.lu.stageByWf[wf]||[]).filter(s=>!['Hired','Rejected','Assessment'].includes(s.name));return head('Pipeline','',`<select data-a="pipeJob"><option value="all" ${A.ui.pipeJob==='all'?'selected':''}>Global Pipeline</option>${jobs.map(j=>`<option value="${j.id}" ${j.id===A.ui.pipeJob?'selected':''}>${esc(j.title)} | ${esc(j.jobCode)}</option>`).join('')}</select>`)+`<div class="wb"><div class="kan">${stages.map(s=>{let items=list.filter(a=>pipelineLaneName(a.stageName)===s.name).sort((a,b)=>{if(a.id===pipeState.focusId)return-1;if(b.id===pipeState.focusId)return 1;return new Date(b.stageEnteredAt||b.updatedAt||b.appliedAt)-new Date(a.stageEnteredAt||a.updatedAt||a.appliedAt)});return `<section class="ks"><div class="ksh"><strong>${esc(s.name)}</strong><span class="pill neu">${items.length}</span></div><div class="ksb" data-stage="${s.id}">${items.map(pipelineCard).join('')}</div></section>`}).join('')}</div></div>`}
function interviews(){return head('Interviews','')+compactGrid('interviews',{title:'Interviews',searchPlaceholder:'Search interviews...',rows:interviewRows,filters:[{key:'status',label:'Status',options:()=>uniq(A.cache.interviews.map(i=>i.status)).map(v=>({value:v,label:v}))}],primary:'interview',primaryLabel:'Create Interview',primaryMin:'Edit',cols:[{key:'roundName',label:'Round'},{key:'candidateName',label:'Candidate'},{key:'jobTitle',label:'Job'},{key:'scheduledStart',label:'Starts',render:r=>fmtd(r.scheduledStart)},{key:'status',label:'Status',render:r=>pill(r.status)},{key:'result',label:'Result',render:r=>pill(r.result)},{key:'feedbackStatus',label:'Feedback',render:r=>pill(r.feedbackStatus)}],rowActions:r=>[{a:'drawer',m:'interviews',label:'Open',min:'View'}]})}
