function pipelineForwardAction(app){let map={Applied:{label:'Screen',target:'Recruiter Screen'},'Recruiter Screen':{label:'Move to Hiring Manager',target:'Hiring Manager'},'Hiring Manager':{label:'Move to Interview',target:'Interview Loop'},'Interview Loop':{label:'Move to Offer',target:'Offer'},Assessment:{label:'Move to Offer',target:'Offer'}};return map[app.stageName]||null}
function pipelineCard(app){let forward=pipelineForwardAction(app),menuItems=[{a:'modal',m:'note',t:'application',rid:app.id,label:'Add Note',min:'Limited'},{a:'bulkReject',id:app.id,label:'Reject',min:'Edit'},{a:'modal',m:'interview',id:app.id,label:'Schedule Interview',module:'interviews',min:'Edit'},{a:'viewResume',id:app.id,label:'View Resume',module:'candidates',min:'Limited'},{a:'bulkStage',id:app.id,label:'Move to specific stage',min:'Edit'},{a:'deleteApplication',id:app.id,label:'Delete',min:'Edit'}].filter(item=>hasModulePermission(item.module||'applications',item.min||'View')),menu=menuItems.length?`<details class="menu"><summary class="btn">&#8943;</summary><div class="mp">${menuItems.map(item=>`<button class="btn"${attr(item)}>${esc(item.label)}</button>`).join('')}</div></details>`:'';return `<article class="kc" draggable="true" data-app="${app.id}"><div class="stk"><strong>${esc(app.candidateName)}</strong><small>${esc(app.jobTitle)}</small></div><div class="km"><span>Fit ${app.fitScore}</span><span>${days(NOW,app.stageEnteredAt)}d in stage</span></div><div class="ka">${forward&&hasModulePermission('applications','Edit')?`<button class="btn" data-a="pipelineForward" data-id="${app.id}" data-stage="${esc(forward.target)}">${esc(forward.label)}</button>`:''}<button class="btn" data-a="drawer" data-m="applications" data-id="${app.id}">Open</button>${menu}</div></article>`}
function reports(){return renderReportsModule()}
function reportFolderLabel(id){return(reportWorkspace().customFolders.find(folder=>folder.id===id)||REPORT_FOLDER_DEFINITIONS.find(folder=>folder.id===id)||{label:id}).label}
function reportModuleLabel(id){return(REPORT_BASE_MODULES.find(([value])=>value===id)||['',id])[1]}
function reportRelativeTime(value){let stamp=new Date(value||NOW),mins=Math.max(0,Math.round((NOW-stamp)/60000));if(mins<1)return'now';if(mins<60)return`${mins} mins ago`;let hrs=Math.round(mins/60);if(hrs<24)return`${hrs} hrs ago`;return`${Math.round(hrs/24)} days ago`}
function reportDefinitions(){let ws=reportWorkspace(),custom=ws.customReports.map(def=>({...def,isSystem:false}));return SYSTEM_REPORT_DEFINITIONS.concat(custom).map(def=>({...def,folderId:ws.folderOverrides[def.id]||def.folderId,isFavorite:ws.favorites.includes(def.id),isDeleted:ws.deleted.includes(def.id),isScheduled:ws.scheduled.includes(def.id)}))}
function reportDefinition(id){return reportDefinitions().find(def=>def.id===id)}
function reportRowsForFolder(folderId,query=''){let ws=reportWorkspace(),rows=reportDefinitions();if(folderId==='recently_deleted')rows=rows.filter(def=>def.isDeleted);else rows=rows.filter(def=>!def.isDeleted);if(folderId==='favorite_reports')rows=rows.filter(def=>def.isFavorite);else if(folderId==='recent_reports')rows=ws.recent.map(id=>rows.find(def=>def.id===id)).filter(Boolean);else if(folderId==='reports_created_by_me')rows=rows.filter(def=>!def.isSystem||def.createdBy===current().fullName);else if(folderId==='scheduled_reports')rows=rows.filter(def=>def.isScheduled);else if(!['all_reports','favorite_reports','recent_reports','reports_created_by_me','scheduled_reports','recently_deleted'].includes(folderId))rows=rows.filter(def=>def.folderId===folderId);if(query){let q=String(query).trim().toLowerCase();rows=rows.filter(def=>`${def.name} ${def.description} ${def.baseModule}`.toLowerCase().includes(q))}if(folderId!=='recent_reports')rows.sort((a,b)=>new Date(b.lastRunAt||0)-new Date(a.lastRunAt||0));return rows}
function reportVisibleDefinitions(){let s=reportState();return reportRowsForFolder(s.folder,s.q)}
function reportRememberRecent(id){let ws=reportWorkspace();ws.recent=uniq([id].concat(ws.recent||[])).slice(0,12);writeReportWorkspace(ws)}
function reportToggleFavorite(id){let ws=reportWorkspace();ws.favorites=ws.favorites.includes(id)?ws.favorites.filter(item=>item!==id):uniq(ws.favorites.concat(id));writeReportWorkspace(ws)}
function reportDeleteIds(ids){if(!ids.length)return;let ws=reportWorkspace();ws.deleted=uniq(ws.deleted.concat(ids));ws.favorites=ws.favorites.filter(id=>!ids.includes(id));writeReportWorkspace(ws);let s=reportState();s.sel=[];if(ids.includes(s.report))s.detail=false}
function reportRestoreIds(ids){if(!ids.length)return;let ws=reportWorkspace();ws.deleted=ws.deleted.filter(id=>!ids.includes(id));writeReportWorkspace(ws);reportState().sel=[]}
function reportCreatableFolders(){return REPORT_FOLDER_DEFINITIONS.filter(folder=>!['all_reports','favorite_reports','recent_reports','reports_created_by_me','scheduled_reports','recently_deleted'].includes(folder.id)).concat(reportWorkspace().customFolders)}
function reportMoveIds(ids,folderId){if(!ids.length||!folderId)return;let ws=reportWorkspace();ws.folderOverrides={...ws.folderOverrides};ids.forEach(id=>ws.folderOverrides[id]=folderId);ws.customReports=ws.customReports.map(def=>ids.includes(def.id)?{...def,folderId}:def);writeReportWorkspace(ws)}
function reportCreateFolder(){if(typeof prompt!=='function')return toast('Folder creation is not available in this browser context.','wt');let name=String(prompt('Folder name','Executive Reports')||'').trim();if(!name)return;let ws=reportWorkspace(),id=`folder_${Date.now().toString(36)}`;ws.customFolders=ws.customFolders.concat({id,label:name});writeReportWorkspace(ws);reportState().folder=id;toast('Report folder created.','okt')}
function reportBlueprintForModule(moduleName){if(moduleName==='job_openings')return{schemaModels:['Job Openings','Applications'],joinPath:['Job Openings -> Applications'],measures:['Record count','Status mix']};if(moduleName==='applications')return{schemaModels:['Applications','Candidates','Job Openings'],joinPath:['Applications -> Candidates','Applications -> Job Openings'],measures:['Stage mix','Status mix','Average fit']};if(moduleName==='interviews')return{schemaModels:['Interviews','Applications'],joinPath:['Interviews -> Applications'],measures:['Interview count','Completion rate']};if(moduleName==='offers')return{schemaModels:['Offers','Applications'],joinPath:['Offers -> Applications'],measures:['Offer count','Acceptance rate']};if(moduleName==='clients')return{schemaModels:['Clients','Job Openings'],joinPath:['Clients -> Job Openings'],measures:['Client count','Opening count']};return{schemaModels:['Candidates','Applications'],joinPath:['Candidates -> Applications'],measures:['Candidate count','Source mix']}}
function reportCreateCustom(){let s=reportState();s.builder=reportBuilderState();s.builder.active=true;s.builder.preview=null;s.builder.step=1;s.detail=false}
