function reportCsvDownload(name,columns,rows){let header=columns.map(col=>col.label).join(','),lines=[header].concat(rows.map(row=>columns.map(col=>JSON.stringify(col.render?col.render(row):row[col.key]??'')).join(','))),blob=new Blob([lines.join('\n')],{type:'text/csv;charset=utf-8;'}),url=URL.createObjectURL(blob),link=document.createElement('a');link.href=url;link.download=`${slug(name||'report')}.csv`;link.click();URL.revokeObjectURL(url)}
function reportExport(id){let def=reportDefinition(id),run=def&&reportRun(def,reportContext());if(def&&run)reportCsvDownload(def.name,run.columns,run.rows)}
function reportBarMarkup(rows){let max=Math.max(1,...rows.map(row=>Number(row.value)||0));return `<div class="reportbars">${rows.map(row=>`<div class="reportbar"><div class="reportbarhead"><strong>${esc(row.label)}</strong><span>${esc(String(row.value))}</span></div><div class="bar"><i style="width:${Math.max(8,Math.round((Number(row.value)||0)/max*100))}%"></i></div><small>${esc(row.note||'')}</small></div>`).join('')}</div>`}
function reportTableMarkup(columns,rows){return `<div class="ts"><div class="tw"><table class="reporttable"><thead><tr>${columns.map(col=>`<th>${esc(col.label)}</th>`).join('')}</tr></thead><tbody>${rows.length?rows.map(row=>`<tr>${columns.map(col=>`<td>${esc(col.render?col.render(row):row[col.key]??'-')}</td>`).join('')}</tr>`).join(''):`<tr><td colspan="${columns.length}"><div class="reportlistempty">No data matches the current report filters.</div></td></tr>`}</tbody></table></div></div>`}
function reportSidebarMarkup(activeFolder){let s=reportState();return `<aside class="panel reportsidebar"><div class="bd"><div class="reportsidehead"><h3>Reports</h3></div><div class="reportsearch" style="margin-top:12px"><input data-a="q" data-k="reports" placeholder="Search folder or report..." value="${esc(s.q)}"></div></div><div class="bd" style="padding-top:0"><div class="reportfolders">${REPORT_FOLDER_DEFINITIONS.concat(reportWorkspace().customFolders).map(folder=>`<button class="reportfolder ${folder.id===activeFolder?'on':''}" data-a="reportFolder" data-id="${folder.id}"><span>${esc(folder.label)}</span><small>${reportRowsForFolder(folder.id,'').length}</small></button>`).join('')}</div></div></aside>`}
function reportListMarkup(rows){let s=reportState(),allSelected=!!rows.length&&rows.every(row=>s.sel.includes(row.id));return `${s.sel.length?`<div class="reportbulk"><strong>${s.sel.length} selected</strong><div class="reportactionsplit"><button class="btn" data-a="reportMoveSelected">Move to Folder</button>${s.folder==='recently_deleted'?`<button class="btn" data-a="reportRestoreSelected">Restore</button>`:`<button class="btnd" data-a="reportDeleteSelected">Delete</button>`}</div></div>`:''}<section class="panel reportlibrary"><div class="hd"><h3>${esc(reportFolderLabel(s.folder))}</h3><span class="sub">${rows.length} reports</span></div><div class="bd" style="padding-top:0"><div class="reporttablewrap"><table class="reporttable"><thead><tr><th style="width:40px"><input type="checkbox" data-a="reportAll" ${allSelected?'checked':''}></th><th style="width:34px"></th><th>Report Name</th><th>Description</th><th>Base Module</th><th>Last Run Date</th></tr></thead><tbody>${rows.length?rows.map(row=>`<tr><td><input type="checkbox" data-a="reportSel" data-id="${row.id}" ${s.sel.includes(row.id)?'checked':''}></td><td><button class="reportstar ${row.isFavorite?'on':''}" data-a="reportFavorite" data-id="${row.id}" title="Favorite">${row.isFavorite?'&#9733;':'&#9734;'}</button></td><td><button class="reportnamebtn" data-a="reportOpen" data-id="${row.id}">${esc(row.name)}</button><div class="reporttiny">${esc(reportFolderLabel(row.folderId))}${row.isScheduled?' | Scheduled':''}</div></td><td>${esc(row.description)}</td><td>${esc(reportModuleLabel(row.baseModule))}</td><td>${esc(reportRelativeTime(row.lastRunAt))}</td></tr>`).join(''):`<tr><td colspan="6"><div class="reportlistempty">No reports match the current folder or search.</div></td></tr>`}</tbody></table></div></div></section>`}
function reportDetailMarkup(def,run){let s=reportState(),filters=`<div class="reportfilters"><select data-a="reportsFilter" data-f="range">${REPORT_RANGE_OPTIONS.map(([value,label])=>`<option value="${value}" ${String(s.range)===value?'selected':''}>${label}</option>`).join('')}</select><select data-a="reportsFilter" data-f="departmentId"><option value="all">All Departments</option>${A.cache.departments.map(d=>`<option value="${d.id}" ${s.departmentId===d.id?'selected':''}>${esc(d.name)}</option>`).join('')}</select><select data-a="reportsFilter" data-f="recruiterId"><option value="all">All Recruiters</option>${A.cache.users.filter(u=>/recruit|partner/i.test(u.role)).map(u=>`<option value="${u.id}" ${s.recruiterId===u.id?'selected':''}>${esc(u.fullName)}</option>`).join('')}</select><select data-a="reportsFilter" data-f="sourceType"><option value="all">All Sources</option>${uniq(A.cache.candidates.map(c=>c.sourceType)).map(source=>`<option value="${esc(source)}" ${s.sourceType===source?'selected':''}>${esc(source)}</option>`).join('')}</select><button class="btn" data-a="reportsReset">Reset</button></div>`;return `<div class="panel"><div class="bd"><div class="reportdetailhead"><div class="reportdetailmeta"><div class="reportcrumb"><button class="btn" data-a="reportBack">Back</button> ${esc(reportFolderLabel(def.folderId))} / ${esc(def.name)}</div><h2>${esc(def.name)}</h2><div class="reporttags"><span class="reporttag">${esc(reportModuleLabel(def.baseModule))}</span><span class="reporttag">${esc(def.chartType||'table')}</span>${def.scheduleLabel?`<span class="reporttag">${esc(def.scheduleLabel)}</span>`:''}${def.isDeleted?`<span class="reporttag">Deleted</span>`:''}</div><p class="reportnote">${esc(def.description)}</p></div><div class="reportactionsplit"><button class="btn" data-a="reportFavorite" data-id="${def.id}">${def.isFavorite?'Unfavorite':'Favorite'}</button><button class="btn" data-a="reportExport" data-id="${def.id}">Export CSV</button>${def.isDeleted?`<button class="btn" data-a="reportRestore" data-id="${def.id}">Restore</button>`:`<button class="btnd" data-a="reportDelete" data-id="${def.id}">Delete</button>`}</div></div><div style="height:14px"></div>${filters}</div></div>${kpis(run.stats.slice(0,4))}<div class="reporttwo"><section class="panel"><div class="hd"><h3>${esc(run.headline.label)}</h3><span class="sub">${esc(run.headline.sub)}</span></div><div class="bd"><strong style="display:block;font-size:1.5rem;margin-bottom:14px">${esc(String(run.headline.value))}</strong>${reportBarMarkup(run.chartRows.slice(0,8))}</div></section><section class="panel"><div class="hd"><h3>Schema Blueprint</h3><span class="sub">How this report joins ATS data</span></div><div class="bd"><div class="rows">${run.summaryRows.slice(0,5).map(row=>`<div class="row"><div><strong>${esc(row.title)}</strong><small>${esc(row.meta)}</small></div>${pill(row.pill)}</div>`).join('')}</div><div style="height:14px"></div><strong style="display:block;margin-bottom:8px">Entities</strong><div class="reporttags">${run.schema.entities.map(entity=>`<span class="reporttag">${esc(entity)}</span>`).join('')}</div><div style="height:14px"></div><strong style="display:block;margin-bottom:8px">Join Path</strong><ul class="reportjoins">${run.schema.joins.map(join=>`<li>${esc(join)}</li>`).join('')}</ul><strong style="display:block;margin:14px 0 8px">Measures</strong><ul class="reportschemafacts">${run.schema.measures.map(measure=>`<li>${esc(measure)}</li>`).join('')}</ul></div></section></div><section class="panel"><div class="hd"><h3>Report Data</h3><span class="sub">${run.rows.length} records | last run ${esc(reportRelativeTime(def.lastRunAt))}</span></div><div class="bd">${reportTableMarkup(run.columns,run.rows)}</div></section>`}
function renderReportsModule(){let s=reportState(),rows=reportVisibleDefinitions(),active=reportDefinition(s.report)||rows[0]||reportDefinitions().find(def=>!def.isDeleted)||null,createAction=hasModulePermission('reports','Edit')?`<button class="btnp" data-a="reportCreate">Create Report</button>`:'';if(active&&!s.report)s.report=active.id;if(s.builder.active&&s.builder.preview)return head('Reports','',createAction)+`<div class="reportshell">${reportSidebarMarkup(s.folder)}<section class="reportmain">${reportBuilderPreviewMarkup()}</section></div>`;if(s.builder.active)return head('Reports','',createAction)+`<div class="reportshell">${reportSidebarMarkup(s.folder)}<section class="reportmain">${reportBuilderMarkup()}</section></div>`;if(s.detail&&active){let run=reportRun(active,reportContext());return head('Reports','',createAction)+`<div class="reportshell">${reportSidebarMarkup(s.folder)}<section class="reportmain">${reportDetailMarkup(active,run)}</section></div>`}return head('Reports','',createAction)+`<div class="reportshell">${reportSidebarMarkup(s.folder)}<section class="reportmain">${reportListMarkup(rows)}<section class="panel"><div class="hd"><h3>Reporting Schema</h3></div><div class="bd"><div class="reportschemaoverview">${SCHEMA_DEFINITION.map(schemaMarkup).join('')}</div></div></section></section></div>`}
function settings(){let s=settingsState();return head('Settings','')+`<div class="settingsshell">${settingsTabNav(s.tab)}<section class="settingsmain">${s.tab==='access'?settingsAccessView():settingsGeneralView()}</section></div>`}
function page(){if(A.ui.route==='dashboard')return dashboard();if(A.ui.route==='candidates')return candidates();if(A.ui.route==='jobs')return jobs();if(A.ui.route==='applications')return applications();if(A.ui.route==='pipeline')return pipeline();if(A.ui.route==='interviews')return interviews();if(A.ui.route==='offers')return offers();if(A.ui.route==='clients')return clients();if(A.ui.route==='reports')return reports();return settings()}
function notesFor(t,id){return(A.lu.notes[t+':'+id]||[]).slice().sort((a,b)=>new Date(b.createdAt)-new Date(a.createdAt))}
function activityFor(t,id){return(A.lu.activity[t+':'+id]||[]).slice().sort((a,b)=>new Date(b.createdAt)-new Date(a.createdAt))}
const JOB_ACTIVITY_FILTERS=[['all','All'],['pipeline','Pipeline'],['interviews','Interviews'],['communication','Communication'],['notes','Notes'],['job','Job Changes'],['system','System']];
function jobActivityState(jobId){return A.ui.s['job_activity_'+jobId]||(A.ui.s['job_activity_'+jobId]={filter:'all'})}
function relatedTaskRows(jobId,appIds,candIds,clientId){return A.cache.tasks.filter(t=>(t.relatedType==='job_opening'&&t.relatedId===jobId)||(t.relatedType==='application'&&appIds.includes(t.relatedId))||(t.relatedType==='candidate'&&candIds.includes(t.relatedId))||(t.relatedType==='client'&&t.relatedId===clientId))}
function activityIcon(cat,code){return `<span class="actico ${cat}">${esc(code)}</span>`}
