if(d.mod==='clients'){let c=A.lu.clients[d.id],jobs=A.cache.job_openings.filter(j=>j.clientId===c.id),apps=A.cache.applications.filter(a=>A.lu.jobs[a.jobOpeningId].clientId===c.id),parent=c.parentClientId?A.lu.clients[c.parentClientId]:null,address=[c.billingStreet||c.street||'',c.billingCity||c.city||'',c.billingProvince||'',c.billingCountry||c.country||''].filter(Boolean).join(', ');tabs=['overview','jobs','applications'];hdr=`<div class="dh"><div><h2>${esc(c.name)}</h2><p>${esc(c.industry)} | ${esc(c.billingCity||c.city||'-')}, ${esc(c.billingCountry||c.country||'-')}</p></div><div class="actions"><button class="btn" data-a="closeDrawer">Close</button></div></div>`;body=d.tab==='jobs'?jobs.length?`<div class="rows">${jobs.map(j=>`<div class="row" data-a="drawer" data-m="jobs" data-id="${j.id}"><div><strong>${esc(j.title)}</strong><small>${esc(j.jobCode)} | ${j.filledCount}/${j.openingsCount} filled</small></div>${pill(j.status)}</div>`).join('')}</div>`:`<div class="empty">No job openings linked.</div>`:d.tab==='applications'?appDrawerTable(apps,'job'):`<div class="dg"><div class="card"><h4>Owner</h4><strong>${esc(A.lu.users[c.ownerUserId].fullName)}</strong><span>${esc(c.phone||'-')} | ${esc(c.fax||'No fax')}</span></div><div class="card"><h4>Type</h4><strong>${esc(c.type)}</strong><span>${esc(c.status)} | ${esc(c.sourceType||'Added by User')}</span></div><div class="card"><h4>Parent Client</h4><strong>${esc(parent?parent.name:'None')}</strong><span>${esc(parent?[parent.industry,parent.type].filter(Boolean).join(' | '):'No parent linked')}</span></div><div class="card"><h4>Website</h4><span>${esc(c.website||'-')}</span></div><div class="card"><h4>Primary Address</h4><span>${esc(address||'-')}</span></div><div class="card"><h4>Notes</h4><span>${esc(c.notes||'No notes yet.')}</span></div></div>`}
