const JOB_FORM_COUNTRIES=['United States','India','United Kingdom','Canada','United Arab Emirates','Singapore'];
const JOB_TYPES=['Full time','Contract','Part time','Internship','Temporary'];
const WORK_EXPERIENCE=['None','0-2 years','3-5 years','5-8 years','8+ years'];
const SALARY_BANDS=[['None',0,0],['50,000 - 80,000',50000,80000],['80,000 - 110,000',80000,110000],['90,000 - 120,000',90000,120000],['120,000 - 160,000',120000,160000],['160,000 - 220,000',160000,220000]];
function jobDate(v,fallback){let d=v?new Date(v):fallback?new Date(fallback):null;return d&&!Number.isNaN(d.getTime())?d.toISOString().slice(0,10):''}
function jobHiringManager(departmentId,currentId){if(currentId)return currentId;return departmentId==='dep_01'?'usr_05':departmentId==='dep_02'||departmentId==='dep_03'?'usr_06':'usr_01'}
function jobRecruiters(){return A.cache.users.filter(u=>/recruit|partner/i.test(u.role))}
function jobContacts(clientId){return A.cache.contacts.filter(c=>!clientId||c.clientId===clientId)}
function jobContactOptions(clientId,selectedId){let contacts=jobContacts(clientId);return contacts.length?contacts.map(c=>`<option value="${c.id}" ${String(selectedId||contacts[0].id)===c.id?'selected':''}>${esc(c.fullName)} | ${esc(c.title)}</option>`).join(''):`<option value="">No client contacts</option>`}
function jobCountryOptions(selected){return JOB_FORM_COUNTRIES.map(v=>`<option value="${esc(v)}" ${String(selected||'United States')===v?'selected':''}>${esc(v)}</option>`).join('')}
function jobSkillCatalog(){return uniq([].concat(...A.cache.job_openings.map(j=>pj(j.requiredSkills,[])),...A.cache.candidates.map(c=>pj(c.skills,[])))).filter(Boolean).sort()}
function jobSkillsValue(j){return pj(j&&j.requiredSkills?j.requiredSkills:'[]',[])}
function jobSkillsMarkup(skills){return skills.length?skills.map(skill=>`<span class="skillchip">${esc(skill)}<button type="button" data-a="jobSkillRemove" data-skill="${esc(skill)}">&times;</button></span>`).join(''):`<span class="skillempty">No skills added yet.</span>`}
function jobSalaryBand(j){if(j&&j.salaryBand)return j.salaryBand;let hit=SALARY_BANDS.find(([,min,max])=>Number(j&&j.salaryMin||0)===min&&Number(j&&j.salaryMax||0)===max);return hit?hit[0]:'90,000 - 120,000'}
function jobFileLabel(value,fallback='No file selected.'){return esc(value||fallback)}
function jobReadonlyMetricField(label,name,value){return `<div class="sheetfield readonlyfield"><label>${label}</label><div class="readonlywrap"><input type="number" min="0" step="1000" name="${name}" readonly value="${esc(value)}"><span class="readonlytip">Read only field</span><span class="readonlylock" aria-hidden="true"><svg viewBox="0 0 24 24" fill="currentColor" width="18" height="18"><path d="M17 9h-1V7a4 4 0 0 0-8 0v2H7a2 2 0 0 0-2 2v8a2 2 0 0 0 2 2h10a2 2 0 0 0 2-2v-8a2 2 0 0 0-2-2Zm-6 0V7a1 1 0 1 1 2 0v2h-2Zm2 6.73V17a1 1 0 1 1-2 0v-1.27a2 2 0 1 1 2 0Z"/></svg></span></div></div>`}
function jobSheet(j){
let clientId=j?j.clientId:A.cache.clients[0].id,client=A.lu.clients[clientId],skills=jobSkillsValue(j),accountManager=j&&j.accountManagerUserId?j.accountManagerUserId:(client?client.ownerUserId:current().id),assigned=pj(j&&j.assignedRecruiterIds?j.assignedRecruiterIds:'[]',j&&j.recruiterUserId?[j.recruiterUserId]:[current().id]),assignedRecruiterId=assigned[0]||current().id,contactId=j&&j.contactId?j.contactId:(jobContacts(clientId)[0]?.id||''),jobSummaryFiles=j&&j.jobSummaryAttachment?j.jobSummaryAttachment:'',otherFiles=j&&j.otherAttachments?j.otherAttachments:'',remote=!!(j&&j.remoteJob),useClient=j?!!j.useClientAddress:true,filledCount=j&&j.filledCount?j.filledCount:0;
return `<div class="modal sheet"><form data-form="job" data-filled-count="${filledCount}"><input type="hidden" name="id" value="${j?j.id:''}"><input type="hidden" name="hiringManagerUserId" value="${esc(jobHiringManager(j?j.departmentId:'dep_01',j?j.hiringManagerUserId:''))}"><div class="sheethead"><div><h2>${j?'Edit Job':'Create Job'}</h2><p>Job opening information, address, forecast details, description, requirements, benefits, and attachments.</p></div><button class="btn sheetsecondary" type="button" data-a="closeModal">Close</button></div><div class="sheetbody"><section class="sheetsection"><h3>Job Opening Information</h3><div class="sheetgrid"><div class="sheetfield"><label>Posting Title <span class="req">*</span></label><input name="title" required value="${esc(j?j.title:'')}" placeholder="Enter the role title"></div><div class="sheetfield"><label>Client Name <span class="req">*</span></label><select name="clientId" data-a="jobClient">${A.cache.clients.map(c=>`<option value="${c.id}" ${String(clientId)===c.id?'selected':''}>${esc(c.name)}</option>`).join('')}</select></div><div class="sheetfield"><label>Department <span class="req">*</span></label><select name="departmentId" data-a="jobDepartment">${A.cache.departments.map(d=>`<option value="${d.id}" ${String(j?j.departmentId:'dep_01')===d.id?'selected':''}>${esc(d.name)}</option>`).join('')}</select></div><div class="sheetfield"><label>Account Manager</label><select name="accountManagerUserId">${A.cache.users.map(u=>`<option value="${u.id}" ${String(accountManager)===u.id?'selected':''}>${esc(u.fullName)}</option>`).join('')}</select></div><div class="sheetfield"><label>Contact Name</label><select name="contactId">${jobContactOptions(clientId,contactId)}</select></div><div class="sheetfield"><label>Job Code</label><input name="jobCode" required value="${esc(j?j.jobCode:'ZR-'+(9000+A.cache.job_openings.length+1))}"></div><div class="sheetfield"><label>Assigned Recruiter</label><select name="assignedRecruiterId">${jobRecruiters().map(u=>`<option value="${u.id}" ${String(assignedRecruiterId)===u.id?'selected':''}>${esc(u.fullName)}</option>`).join('')}</select></div><div class="sheetfield"><label>Date Opened</label><input type="date" name="dateOpened" value="${jobDate(j&&j.dateOpened,NOW)}"></div><div class="sheetfield"><label>Target Date <span class="req">*</span></label><input type="date" name="targetCloseDate" required value="${jobDate(j&&j.targetCloseDate,from(30))}"></div><div class="sheetfield"><label>Job Type</label><select name="jobType">${JOB_TYPES.map(v=>`<option value="${v}" ${String(j&&j.jobType||'Full time')===v?'selected':''}>${v}</option>`).join('')}</select></div><div class="sheetfield"><label>Job Opening Status</label><select name="status">${['Open','On Hold','Closed','Filled'].map(v=>`<option value="${v}" ${(j&&j.status===v)||(!j&&v==='Open')?'selected':''}>${v}</option>`).join('')}</select></div><div class="sheetfield"><label>Work Experience</label><select name="workExperience">${WORK_EXPERIENCE.map(v=>`<option value="${v}" ${String(j&&j.workExperience||'None')===v?'selected':''}>${v}</option>`).join('')}</select></div><div class="sheetfield"><label>Industry <span class="req">*</span></label><select name="industry">${uniq(A.cache.clients.map(c=>c.industry)).sort().map(v=>`<option value="${v}" ${String(j&&j.industry||client?.industry||'')===v?'selected':''}>${esc(v)}</option>`).join('')}</select></div><div class="sheetfield"><label>Salary</label><input name="salaryBand" list="salaryBandOptions" value="${esc(jobSalaryBand(j))}" placeholder="Type or choose a salary range"><datalist id="salaryBandOptions">${SALARY_BANDS.map(([label])=>`<option value="${esc(label)}"></option>`).join('')}</datalist></div><div class="sheetfield full"><label>Required Skills</label><div class="skillpicker"><div class="skillentry"><input type="text" name="skillSearch" data-a="jobSkillSearch" list="jobSkillOptions" placeholder="Search and add skills"><button class="btn" type="button" data-a="jobSkillAdd">Add Skill</button></div><input type="hidden" name="requiredSkills" value="${esc(JSON.stringify(skills))}"><datalist id="jobSkillOptions">${jobSkillCatalog().map(skill=>`<option value="${esc(skill)}"></option>`).join('')}</datalist><div class="skillchips" data-role="skillchips">${jobSkillsMarkup(skills)}</div></div></div></div></section><section class="sheetsection"><div class="sheettoggles"><h3>Address Information</h3><label class="checkline"><input type="checkbox" name="useClientAddress" data-a="jobUseClientAddress" ${useClient?'checked':''}>Use Client Address</label><label class="checkline"><input type="checkbox" name="remoteJob" data-a="jobRemote" ${remote?'checked':''}>Remote Job</label></div><div class="sheetgrid"><div class="sheetfield"><label>City</label><input name="city" value="${esc(j?j.city:(useClient&&client?client.city:''))}"></div><div class="sheetfield"><label>Province</label><input name="province" value="${esc(j&&j.province?j.province:'')}"></div><div class="sheetfield"><label>Country</label><select name="country">${jobCountryOptions(j&&j.country?j.country:(useClient&&client?client.country:'United States'))}</select></div><div class="sheetfield"><label>Postal Code</label><input name="postalCode" value="${esc(j&&j.postalCode?j.postalCode:'')}"></div></div></section><section class="sheetsection"><h3>Forecast Details</h3><div class="sheetgrid"><div class="sheetfield"><label>Revenue per Position</label><input type="number" min="0" step="1000" name="revenuePerPosition" data-a="jobForecast" value="${esc(j&&j.revenuePerPosition?j.revenuePerPosition:0)}"></div>${jobReadonlyMetricField('Expected Revenue','expectedRevenue',j&&j.expectedRevenue?j.expectedRevenue:0)}${jobReadonlyMetricField('Actual Revenue','actualRevenue',j&&j.actualRevenue?j.actualRevenue:0)}${jobReadonlyMetricField('Missed Revenue','missedRevenue',j&&j.missedRevenue?j.missedRevenue:0)}<div class="sheetfield"><label>Number of Positions</label><input type="number" min="1" max="20" name="numberOfPositions" data-a="jobForecast" value="${esc(j&&j.numberOfPositions?j.numberOfPositions:j&&j.openingsCount?j.openingsCount:1)}"></div><div class="sheetfield"><label>Priority</label><select name="priority">${['Low','Medium','High','Critical'].map(v=>`<option value="${v}" ${(j&&j.priority===v)||(!j&&v==='Low')?'selected':''}>${v}</option>`).join('')}</select></div></div></section><section class="sheetsection"><h3>Description Information</h3><div class="sheetcols"><div class="editorcard"><div class="editortop"><strong>Job Description</strong><span>32,000 characters</span></div><textarea name="jobDescription" placeholder="Describe the role, mission, and responsibilities.">${esc(j&&j.jobDescription?j.jobDescription:j&&j.jdSummary?j.jdSummary:'')}</textarea></div><div class="editorcard"><div class="editortop"><strong>Requirements</strong><span>Key qualifications</span></div><textarea name="requirementsText" placeholder="List the must-have experience and competencies.">${esc(j&&j.requirementsText?j.requirementsText:pj(j&&j.requiredSkills?j.requiredSkills:'[]',[]).join(', '))}</textarea></div></div><div class="editorcard"><div class="editortop"><strong>Benefits</strong><span>Candidate value proposition</span></div><textarea name="benefitsText" placeholder="Add benefits, perks, and team highlights.">${esc(j&&j.benefitsText?j.benefitsText:'')}</textarea></div></section><section class="sheetsection"><h3>Attachment Information</h3><div class="uploadgrid"><div class="sheetupload"><label>Job Summary</label><div class="filebox"><input type="file" name="jobSummaryFile" data-a="jobFile"><div class="filename" data-role="filename" data-fallback="${esc(jobSummaryFiles||'No file selected.')}">${jobFileLabel(jobSummaryFiles)}</div></div></div><div class="sheetupload"><label>Others</label><div class="filebox"><input type="file" name="otherFiles" data-a="jobFile" multiple><div class="filename" data-role="filename" data-fallback="${esc(otherFiles||'No file selected.')}">${jobFileLabel(otherFiles)}</div></div></div></div></section></div><div class="sheetfoot"><button class="btn sheetsecondary" type="button" data-a="closeModal">Cancel</button><button class="btnp sheetprimary" type="submit">Save Job</button></div></form></div>`
}
function jobSkillsFromForm(form){return pj(form.querySelector('[name="requiredSkills"]').value||'[]',[])}
function setJobSkills(form,skills){let hidden=form.querySelector('[name="requiredSkills"]'),chips=form.querySelector('[data-role="skillchips"]');hidden.value=JSON.stringify(skills);chips.innerHTML=jobSkillsMarkup(skills)}
function syncJobClient(form){let clientId=form.querySelector('[name="clientId"]').value,client=A.lu.clients[clientId],contact=form.querySelector('[name="contactId"]'),currentContact=contact.value;contact.innerHTML=jobContactOptions(clientId,currentContact);if(!contact.value&&contact.options.length)contact.value=contact.options[0].value;let industry=form.querySelector('[name="industry"]');if(industry&&client&&[...industry.options].some(o=>o.value===client.industry))industry.value=client.industry;let account=form.querySelector('[name="accountManagerUserId"]');if(account&&client)account.value=client.ownerUserId;syncJobLocation(form)}
function syncJobLocation(form){let remote=form.querySelector('[name="remoteJob"]').checked,useClient=form.querySelector('[name="useClientAddress"]').checked,client=A.lu.clients[form.querySelector('[name="clientId"]').value],city=form.querySelector('[name="city"]'),province=form.querySelector('[name="province"]'),country=form.querySelector('[name="country"]'),postal=form.querySelector('[name="postalCode"]');if(remote){city.value='Remote';province.value='';postal.value='';city.disabled=true;province.disabled=true;postal.disabled=true;if(!country.value)country.value='United States';return}city.disabled=false;province.disabled=false;postal.disabled=false;if(useClient&&client){city.value=client.city||'';country.value=client.country||'United States'}}
function syncJobForecast(form){let revenue=Number(form.querySelector('[name="revenuePerPosition"]').value||0),positions=Number(form.querySelector('[name="numberOfPositions"]').value||0),filled=Number(form.dataset.filledCount||0),expected=revenue*positions,actual=revenue*Math.min(filled,positions),missed=Math.max(expected-actual,0);form.querySelector('[name="expectedRevenue"]').value=expected||0;form.querySelector('[name="actualRevenue"]').value=actual||0;form.querySelector('[name="missedRevenue"]').value=missed||0}
