const INTERVIEW_REMINDERS=['-None-','15 minutes before','30 minutes before','1 hour before','1 day before'];
function interviewIcon(kind){if(kind==='video')return `<svg viewBox="0 0 24 24" fill="currentColor" aria-hidden="true"><path d="M3 7a2 2 0 0 1 2-2h8a2 2 0 0 1 2 2v1.3l3.46-2A1 1 0 0 1 20 7.17v9.66a1 1 0 0 1-1.54.87L15 15.7V17a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V7Z"/></svg>`;return `<svg viewBox="0 0 24 24" fill="currentColor" aria-hidden="true"><path d="M12 12a4 4 0 1 0-4-4 4 4 0 0 0 4 4Zm-6.5 8a1.5 1.5 0 0 1-1.5-1.5C4 15.46 7.13 13 12 13s8 2.46 8 5.5A1.5 1.5 0 0 1 18.5 20Zm-1.7-7.88A3.3 3.3 0 1 0 .5 8.82a3.3 3.3 0 0 0 3.3 3.3Zm15.4 0a3.3 3.3 0 1 0-3.3-3.3 3.3 3.3 0 0 0 3.3 3.3ZM.47 18.28a1.29 1.29 0 0 0 1.28 1.29H4.7a7.33 7.33 0 0 1 1.37-3.71c-2.64.18-5.6 1.2-5.6 2.42Zm17.46-2.42a7.33 7.33 0 0 1 1.37 3.71h2.95a1.29 1.29 0 0 0 1.28-1.29c0-1.22-2.96-2.24-5.6-2.42Z"/></svg>`}
function interviewFieldIcon(name){if(name==='candidate')return `<svg viewBox="0 0 24 24" fill="currentColor" width="20" height="20"><path d="M12 12a4 4 0 1 0-4-4 4 4 0 0 0 4 4Zm0 2c-4.42 0-8 2.24-8 5v1h16v-1c0-2.76-3.58-5-8-5Z"/></svg>`;if(name==='job')return `<svg viewBox="0 0 24 24" fill="currentColor" width="20" height="20"><path d="M9 6V4a1 1 0 0 1 1-1h4a1 1 0 0 1 1 1v2h4a2 2 0 0 1 2 2v9a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2Zm2 0h2V5h-2Zm-6 5h14V8H5Zm0 2v4h14v-4Z"/></svg>`;if(name==='client')return `<svg viewBox="0 0 24 24" fill="currentColor" width="20" height="20"><path d="M3 21V7a1 1 0 0 1 1-1h7v15Zm9 0V3a1 1 0 0 1 1-1h7a1 1 0 0 1 1 1v18Zm-6-9h3v2H6Zm0 4h3v2H6Zm9-8h3v2h-3Zm0 4h3v2h-3Zm0 4h3v2h-3Z"/></svg>`;if(name==='location')return `<svg viewBox="0 0 24 24" fill="currentColor" width="20" height="20"><path d="M12 22s7-7.33 7-12a7 7 0 1 0-14 0c0 4.67 7 12 7 12Zm0-9a3 3 0 1 1 3-3 3 3 0 0 1-3 3Z"/></svg>`;if(name==='assessment')return `<svg viewBox="0 0 24 24" fill="currentColor" width="20" height="20"><path d="M6 2h9l5 5v15a2 2 0 0 1-2 2H6a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2Zm8 1.5V8h4.5ZM8 12h8v1.5H8Zm0 4h8V17.5H8Zm0-8h4v1.5H8Z"/></svg>`;return `<svg viewBox="0 0 24 24" fill="currentColor" width="20" height="20"><path d="M4 4h16v16H4z"/></svg>`}
function interviewApps(){return applicationRows().filter(a=>!['Rejected','Withdrawn'].includes(a.overallStatus)).slice(0,160)}
function interviewAppId(id){let rows=interviewApps();return A.lu.apps[id]?id:(rows[0]?rows[0].id:'')}
function interviewContext(id){let appId=interviewAppId(id),app=A.lu.apps[appId];if(!app)return{appId:'',app:null,candidate:null,job:null,client:null};let job=A.lu.jobs[app.jobOpeningId],candidate=A.lu.cand[app.candidateId],client=job?A.lu.clients[job.clientId]:null;return{appId,app,candidate,job,client}}
function interviewDate(v){return dtlocal(v||from(2)).slice(0,10)}
function interviewTime(v){return dtlocal(v||from(2)).slice(11,16)}
function interviewDateTime(date,time){let out=new Date(`${date}T${time||'09:00'}`);return Number.isNaN(out.getTime())?new Date(from(2)):out}
function interviewAddMinutes(date,minutes){return new Date(date.getTime()+minutes*60000)}
function interviewAssessmentOptions(appId){let titles=(A.lu.byAppAsm[appId]||[]).map(x=>x.title);return uniq(titles.concat(['Screening Interview','General Assessment']))}
function interviewApplicationPicker(id){return `<div class="intappselect"><label>Linked Application</label><select name="applicationId" data-a="interviewApplication">${interviewApps().map(a=>`<option value="${a.id}" ${String(id)===a.id?'selected':''}>${esc(a.candidateName)} -> ${esc(a.jobTitle)}</option>`).join('')}</select></div>`}
function interviewReadOnlyField(label,name,value,required=false){return `<div class="intfield"><label>${label}${required?` <span class="intreq">*</span>`:''}</label><div class="intinputicon"><input class="intreadonly" readonly value="${esc(value||'')}"><span class="intsuffix">${interviewFieldIcon(name)}</span></div></div>`}
function interviewEditableField(label,fieldName,iconName,value,required=false){return `<div class="intfield"><label>${label}${required?` <span class="intreq">*</span>`:''}</label><div class="intinputicon"><input name="${fieldName}" value="${esc(value||'')}" ${required?'required':''}><span class="intsuffix">${interviewFieldIcon(iconName)}</span></div></div>`}
function interviewChooserModal(m){return `<div class="modal intmodal"><div class="intheader"><div><h2 class="inttitle">Create Interview</h2></div><button class="intcloseplain" type="button" data-a="closeModal">&times;</button></div><div class="intbody intchooser"><button class="intcard" type="button" data-a="interviewMode" data-mode="inperson"><span class="intcardicon">${interviewIcon('inperson')}</span><span class="intcardbody"><h3>In-person Interview</h3><p>Schedule and conduct interviews with candidates, interviewers, recruiters and contacts.</p></span></button><button class="intcard" type="button" data-a="interviewMode" data-mode="video"><span class="intcardicon">${interviewIcon('video')}</span><span class="intcardbody"><h3>Video Interview</h3><p>Schedule and conduct both recorded and live video interviews with candidates, recruiters and interviewers.</p></span></button></div></div>`}
function interviewInPersonModal(m){let ctx=interviewContext(m.id),start=ctx.app&&ctx.app.lastInterviewAt?new Date(ctx.app.lastInterviewAt):from(2),end=shift(start,0,1),ownerId=ctx.job?ctx.job.recruiterUserId:current().id;return `<div class="modal intmodal"><form data-form="interview"><div class="intheader"><div class="intheadleft"><button class="intback" type="button" data-a="interviewBack" data-to="chooser">&#8592;</button><div><h2 class="inttitle">Create Interview</h2><p class="intsubtitle">In-person interview</p></div></div><button class="intcloseplain" type="button" data-a="closeModal">&times;</button></div><div class="intflatbody"><input type="hidden" name="interviewKind" value="inperson"><input type="hidden" name="applicationId" value="${esc(ctx.appId)}"><section class="intflatsection"><h3>Interview Information</h3><div class="intflatgrid"><div class="intflatfield"><label>Interview Name <span class="intreq">*</span></label><select name="interviewName">${INTERVIEW_NAMES.map(v=>`<option value="${v}">${v}</option>`).join('')}</select></div>${interviewEditableField('Candidate Name','candidateName','candidate',ctx.candidate&&ctx.candidate.fullName,true).replace('intfield','intflatfield')}${interviewEditableField('Client Name','clientName','client',ctx.client&&ctx.client.name).replace('intfield','intflatfield')}${interviewEditableField('Posting Title','postingTitle','job',ctx.job&&ctx.job.title,true).replace('intfield','intflatfield')}<div class="intflatfield"><label>From <span class="intreq">*</span></label><div class="intpair"><input type="date" name="startDate" value="${interviewDate(start)}" required><input type="time" name="startTime" value="${interviewTime(start)}" required></div></div><div class="intflatfield"><label>To <span class="intreq">*</span></label><div class="intpair"><input type="date" name="endDate" value="${interviewDate(end)}" required><input type="time" name="endTime" value="${interviewTime(end)}" required></div></div><div class="intflatfield"><label>Interviewer(s) <span class="intreq">*</span></label><input name="interviewers" required></div><div class="intflatfield"><label>Interview Owner</label><select name="interviewOwner">${A.cache.users.map(u=>`<option value="${u.id}" ${u.id===ownerId?'selected':''}>${esc(u.fullName)}</option>`).join('')}</select></div><div class="intflatfield"><label>Location</label><div class="intinputicon"><input name="location" placeholder=""><span class="intsuffix">${interviewFieldIcon('location')}</span></div></div><div class="intflatfield"><label>Schedule Comments</label><textarea name="scheduleComments"></textarea></div><div class="intflatfield"><label>Assessment Name</label><div class="intinputicon"><select name="assessmentName"><option value=""></option>${interviewAssessmentOptions(ctx.appId).map(v=>`<option value="${esc(v)}">${esc(v)}</option>`).join('')}</select><span class="intsuffix">${interviewFieldIcon('assessment')}</span></div></div></div></section><section class="intflatsection"><h3>Attachment Information</h3><div class="intflatattach"><label>Others</label><input type="file" name="otherFiles" multiple></div></section></div><div class="intflatfooter"><button class="intsecondary" type="button" data-a="closeModal">Cancel</button><button class="intprimary" type="submit">Schedule</button></div></form></div>`}
function interviewVideoProviderModal(m){let provider=m.provider||adminSettings().defaultVideoProvider;return `<div class="modal intmodal"><div class="intheader"><div class="intheadleft"><button class="intback" type="button" data-a="interviewBack" data-to="chooser">&#8592;</button><div><h2 class="inttitle">Create Interview</h2></div></div><button class="intcloseplain" type="button" data-a="closeModal">&times;</button></div><div class="intbody"><div class="intcard intprovider"><span class="intcardicon">${interviewIcon('video')}</span><span class="intcardbody"><h3>Video Interview</h3><p>Schedule and conduct both recorded and live video interviews with candidates, recruiters and interviewers.</p><div class="intprovidercontrols"><label class="intproviderlabel">Select Provider</label><select name="videoProvider">${VIDEO_PROVIDER_OPTIONS.map(v=>`<option value="${esc(v)}" ${v===provider?'selected':''}>${esc(v)}</option>`).join('')}</select></div><div class="intcta"><button class="intprimary" type="button" data-a="videoProceed">Proceed</button></div></span></div></div></div>`}
function interviewVideoModal(m){let cfg=adminSettings(),ctx=interviewContext(m.id),start=ctx.app&&ctx.app.lastInterviewAt?new Date(ctx.app.lastInterviewAt):from(2),provider=m.provider||cfg.defaultVideoProvider,name=provider.includes('Recorded')?'Recorded Video Interview':'Live Video Interview',appField=m.id?`<input type="hidden" name="applicationId" value="${esc(ctx.appId)}">`:`<div class="intgrid" style="padding:0 28px">${interviewApplicationPicker(ctx.appId)}</div>`;return `<div class="modal intmodal intvideoform"><form data-form="interview"><div class="intvideoheader"><div class="intheadleft"><button class="intback" type="button" data-a="interviewBack" data-to="provider">&#8592;</button><div><h2 class="inttitle">${esc(provider)}</h2></div></div><div class="intheaderlinks"><button class="intcloseplain" type="button" data-a="closeModal">&times;</button></div></div><div class="intbody"><input type="hidden" name="interviewKind" value="video"><input type="hidden" name="videoProvider" value="${esc(provider)}"><div class="intnote"><strong>Note:</strong><ul><li>Live interviews can be scheduled only if the candidate record has an email address.</li><li>After scheduling, the interviewer and candidate will receive the link to attend the interview by email.</li></ul></div>${appField}<div class="intgrid"><div class="intfield"><label>Interview Name <span class="intreq">*</span></label><input name="interviewName" value="${esc(name)}" required></div><div class="intfield"><label>Date and Time <span class="intreq">*</span></label><div class="inttriplet"><input type="date" name="scheduledDate" value="${interviewDate(start)}" required><input type="time" name="scheduledTime" value="${interviewTime(start)}" required><select name="durationMinutes">${[30,45,60,90].map(v=>`<option value="${v}" ${Number(cfg.defaultInterviewDuration||45)===v?'selected':''}>${v} min</option>`).join('')}</select></div></div>${interviewReadOnlyField('Posting Title','job',ctx.job&&ctx.job.title,true)}${interviewReadOnlyField('Candidate Name','candidate',ctx.candidate&&ctx.candidate.fullName,true)}<div class="intfield"><label>Interviewer(s) <span class="intreq">*</span></label><input name="interviewers" placeholder="Add interviewer names" required></div><div class="intfield"><label>Assessment Name</label><div class="intinputicon"><select name="assessmentName"><option value="">Select assessment</option>${interviewAssessmentOptions(ctx.appId).map(v=>`<option value="${esc(v)}">${esc(v)}</option>`).join('')}</select><span class="intsuffix">${interviewFieldIcon('assessment')}</span></div></div>${interviewReadOnlyField('Client Name','client',ctx.client&&ctx.client.name)}<div class="intfield"><label>Reminder</label><select name="reminder">${INTERVIEW_REMINDERS.map(v=>`<option value="${esc(v)}" ${cfg.defaultReminder===v?'selected':''}>${esc(v)}</option>`).join('')}</select></div><div class="intfield"><label>Schedule Comments</label><textarea name="scheduleComments" placeholder="Share context for the panel and candidate"></textarea></div></div></div><div class="intfooter"><button class="intsecondary" type="button" data-a="closeModal">Cancel</button><div class="intsplitbtn"><button type="submit">Schedule</button><button type="submit">&#9662;</button></div></div></form></div>`}
function modal(){let m=A.ui.modal,root=document.getElementById('modalRoot');if(!m){root.innerHTML='';return}let close=`<button class="btn" type="button" data-a="closeModal">Cancel</button>`,html='';
if(m.type==='candidate'){let c=m.id?A.lu.cand[m.id]:null;html=candidateSheet(c)}
if(m.type==='job'){let j=m.id?A.lu.jobs[m.id]:null;html=jobSheet(j)}
if(m.type==='client'){let c=m.id?A.lu.clients[m.id]:null;html=clientSheet(c)}
if(m.type==='submitCandidate'){html=`<div class="modal"><form data-form="submitCandidate"><div class="mh"><div><h2>Submit Candidate to Job</h2><p>Create a new application from the candidate database.</p></div><button class="btn" type="button" data-a="closeModal">Close</button></div><div class="mb"><div class="fg"><div class="field"><label>Candidate</label><select name="candidateId">${A.cache.candidates.map(c=>`<option value="${c.id}" ${String(m.id||'')===c.id?'selected':''}>${esc(c.fullName)}</option>`).join('')}</select></div><div class="field"><label>Job Opening</label><select name="jobOpeningId">${A.cache.job_openings.filter(j=>j.status!=='Closed').map(j=>`<option value="${j.id}">${esc(j.title)}</option>`).join('')}</select></div></div></div><div class="mf">${close}<button class="btnp" type="submit">Create Application</button></div></form></div>`}
if(m.type==='stagebulk'){let ids=(m.ids||state('applications').sel),single=ids.length===1;html=`<div class="modal"><form data-form="stagebulk"><div class="mh"><div><h2>${single?'Move Stage':'Bulk Move Stage'}</h2><p>${single?'Move this application to a new pipeline stage.':'Move selected applications to a new pipeline stage.'}</p></div><button class="btn" type="button" data-a="closeModal">Close</button></div><div class="mb"><input type="hidden" name="ids" value="${esc(ids.join(','))}"><div class="field"><label>Target Stage</label><select name="stageName">${['Applied','Recruiter Screen','Hiring Manager','Interview Loop','Assessment','Offer'].map(v=>`<option value="${v}">${v}</option>`).join('')}</select></div></div><div class="mf">${close}<button class="btnp" type="submit">${single?'Move Stage':'Move Applications'}</button></div></form></div>`}
if(m.type==='assignowner'){let ids=m.ids?m.ids:state('applications').sel,single=ids.length===1;html=`<div class="modal"><form data-form="assignowner"><div class="mh"><div><h2>Assign Owner</h2><p>${single?'Reassign this application to a new owner.':'Reassign selected applications.'}</p></div><button class="btn" type="button" data-a="closeModal">Close</button></div><div class="mb"><input type="hidden" name="ids" value="${esc(ids.join(','))}"><div class="field"><label>Owner</label><select name="ownerUserId">${A.cache.users.map(u=>`<option value="${u.id}" ${u.id===current().id?'selected':''}>${esc(u.fullName)}</option>`).join('')}</select></div></div><div class="mf">${close}<button class="btnp" type="submit">Assign Owner</button></div></form></div>`}
if(m.type==='rejectapps'){let ids=(m.ids||state('applications').sel),single=ids.length===1;html=`<div class="modal"><form data-form="rejectapps"><div class="mh"><div><h2>${single?'Reject Application':'Reject Applications'}</h2><p>${single?'Close this application with a consistent reason.':'Close selected applications with a consistent reason.'}</p></div><button class="btn" type="button" data-a="closeModal">Close</button></div><div class="mb"><input type="hidden" name="ids" value="${esc(ids.join(','))}"><div class="field"><label>Reason</label><select name="rejectionReasonId">${A.cache.rejection_reasons.map(r=>`<option value="${r.id}">${esc(r.label)}</option>`).join('')}</select></div></div><div class="mf">${close}<button class="btnd" type="submit">${single?'Reject Application':'Reject Applications'}</button></div></form></div>`}
if(m.type==='interview'){html=!m.kind?interviewChooserModal(m):m.kind==='inperson'?interviewInPersonModal(m):m.step==='form'?interviewVideoModal(m):interviewVideoProviderModal(m)}
if(m.type==='rescheduleInterview'){let i=A.cache.interviews.find(x=>x.id===m.interviewId),c=A.lu.cand[i.candidateId],j=A.lu.jobs[i.jobOpeningId];html=`<div class="modal"><form data-form="rescheduleInterview"><div class="mh"><div><h2>Reschedule Interview</h2><p>${esc(c.fullName)} -> ${esc(j.title)}</p></div><button class="btn" type="button" data-a="closeModal">Close</button></div><div class="mb"><input type="hidden" name="interviewId" value="${esc(i.id)}"><div class="fg"><div class="field"><label>Round</label><select name="roundName">${['Recruiter Intro','Technical Screen','Hiring Manager','Panel','Final'].map(v=>`<option value="${v}" ${i.roundName===v?'selected':''}>${v}</option>`).join('')}</select></div><div class="field"><label>Type</label><select name="interviewType">${['Video','Phone','Onsite','Panel'].map(v=>`<option value="${v}" ${i.interviewType===v?'selected':''}>${v}</option>`).join('')}</select></div><div class="field full"><label>New Start</label><input type="datetime-local" name="scheduledStart" value="${dtlocal(i.scheduledStart)}"></div></div></div><div class="mf">${close}<button class="btnp" type="submit">Save Changes</button></div></form></div>`}
if(m.type==='note'){html=`<div class="modal"><form data-form="note"><div class="mh"><div><h2>Add Note</h2><p>Attach a structured note to the selected record.</p></div><button class="btn" type="button" data-a="closeModal">Close</button></div><div class="mb"><input type="hidden" name="relatedType" value="${esc(m.t||'application')}"><input type="hidden" name="relatedId" value="${esc(m.rid||'')}"><div class="field full"><label>Body</label><textarea name="body" required></textarea></div><div class="field"><label>Visibility</label><select name="visibility"><option>Team</option><option>Private</option></select></div></div><div class="mf">${close}<button class="btnp" type="submit">Save Note</button></div></form></div>`}
if(m.type==='saveview'){html=`<div class="modal"><form data-form="saveview"><div class="mh"><div><h2>Save Current View</h2><p>Persist filters and sort for this module.</p></div><button class="btn" type="button" data-a="closeModal">Close</button></div><div class="mb"><input type="hidden" name="moduleName" value="${esc(m.k||A.ui.route)}"><div class="field"><label>View Name</label><input name="name" required></div></div><div class="mf">${close}<button class="btnp" type="submit">Save View</button></div></form></div>`}
if(m.type==='quick'){html=`<div class="modal"><div class="mh"><div><h2>Quick Add</h2><p>Create records directly from the workbench.</p></div><button class="btn" type="button" data-a="closeModal">Close</button></div><div class="mb"><div class="rows"><div class="row"><div><strong>Candidate</strong><small>Create a new candidate profile.</small></div><button class="btnp" data-a="swapModal" data-m="candidate">Open</button></div><div class="row"><div><strong>Job Opening</strong><small>Create a new requisition with ownership and target date.</small></div><button class="btnp" data-a="swapModal" data-m="job">Open</button></div><div class="row"><div><strong>Interview</strong><small>Schedule an interview linked to an application.</small></div><button class="btnp" data-a="swapModal" data-m="interview">Open</button></div></div></div></div>`}
root.innerHTML=`<div class="scrim on ${['job','candidate'].includes(m.type)?'sheet':''}">${html}</div>`;if(m.type==='job'){let form=root.querySelector('form[data-form="job"]');if(form){syncJobClient(form);syncJobForecast(form)}}}
function toasts(){document.getElementById('toastRoot').innerHTML=`<div class="toastbox">${A.ui.toasts.map(t=>`<div class="toast ${t.tone}">${esc(t.msg)}</div>`).join('')}</div>`}
function toast(msg,tone='it'){let id=Date.now()+Math.random();A.ui.toasts.push({id,msg,tone});toasts();setTimeout(()=>{A.ui.toasts=A.ui.toasts.filter(t=>t.id!==id);toasts()},2400)}
function rememberUiState(){let pageEl=document.querySelector('.page');A.ui.pageScroll={route:A.ui.route,top:pageEl?pageEl.scrollTop:0,left:pageEl?pageEl.scrollLeft:0};if(A.ui.route==='pipeline'){let board=document.querySelector('.kan');if(board)A.ui.pipeScrollLeft=board.scrollLeft}}
function restoreUiState(){let pageEl=document.querySelector('.page'),pageScroll=A.ui.pageScroll;if(pageEl&&pageScroll&&pageScroll.route===A.ui.route){pageEl.scrollTop=pageScroll.top||0;pageEl.scrollLeft=pageScroll.left||0}if(A.ui.route==='pipeline'){let board=document.querySelector('.kan');if(board){board.scrollLeft=A.ui.pipeScrollLeft||0;if(!board.dataset.boundScroll){board.addEventListener('scroll',()=>{A.ui.pipeScrollLeft=board.scrollLeft},{passive:true});board.dataset.boundScroll='1'}}}}
function rerenderAndPreserveInput(el){let meta=el?{a:el.dataset.a||'',k:el.dataset.k||'',value:String(el.value||''),start:typeof el.selectionStart==='number'?el.selectionStart:null,end:typeof el.selectionEnd==='number'?el.selectionEnd:null}:null;render();if(!meta)return;setTimeout(()=>{let selector=meta.a==='q'?`[data-a="q"][data-k="${meta.k}"]`:`[data-a="${meta.a}"]`,input=document.querySelector(selector);if(!input)return;input.focus();if(input.value!==meta.value)input.value=meta.value;if(typeof meta.start==='number'&&typeof input.setSelectionRange==='function'){let end=typeof meta.end==='number'?meta.end:meta.start,len=input.value.length;input.setSelectionRange(Math.min(meta.start,len),Math.min(end,len))}},0)}
function render(){ensureRouteAccess();rememberUiState();document.getElementById('app').innerHTML=shell(page());drawer();modal();toasts();bindDnD();restoreUiState()}
async function saveRow(store,row){await A.db.put(store,row);let arr=A.cache[store],i=arr.findIndex(x=>x.id===row.id);if(i>=0)arr[i]=row;else arr.push(row);buildLookups()}
async function replaceStoreRows(store,rows){await A.db.clear(store);if(rows.length)await A.db.bulk(store,rows);A.cache[store]=rows.slice();buildLookups()}
async function appendActivity(entry){await saveRow('activity_log',{id:nextId('act',A.cache.activity_log.length),entityType:entry.entityType,entityId:entry.entityId,actionType:entry.actionType||entry.title||'Activity',actorUserId:entry.actorUserId||current().id,message:entry.message||'',category:entry.category||'',iconKey:entry.iconKey||'',title:entry.title||'',contextText:entry.contextText||'',stageName:entry.stageName||'',statusValue:entry.statusValue||'',linkType:entry.linkType||'',linkId:entry.linkId||'',metaJson:JSON.stringify(entry.meta||{}),createdAt:entry.createdAt||iso(NOW)})}
function appStageByName(jobId,name){let j=A.lu.jobs[jobId];return j?(A.lu.stageByWf[j.workflowId]||[]).find(s=>s.name===name):null}
function applicationStatusForStage(stageName){return stageName==='Offer'?'Offered':stageName==='Assessment'?'Assessment':stageName==='Interview Loop'?'Interview':'Active'}
